1	// CsrTrigger pre-scans an instruction buffer (typically the loadable
2	// executable segments of an ELF) for `csrw 0x7C0, *` instructions and
3	// records their PCs. At retire time the simulator queries lookup(pc) to
4	// decide whether to drain state and hand back to QEMU.
5	//
6	// Pure logic: no SystemC, no DMI bus. Decoupled from GPR access -- the
7	// caller resolves runtime-kind rs1 values via decode_csrrw_rs1.
8	
9	#pragma once
10	
11	#include "hybrid/insn_match.h"
12	
13	#include <cstddef>
14	#include <cstdint>
15	#include <cstring>
16	#include <optional>
17	#include <span>
18	#include <unordered_map>
19	
20	namespace hybrid
21	{
22	
23	struct CsrTriggerHit
24	{
25	  hybrid_handoff_kind kind;
26	  uint32_t insn;
27	};
28	
29	inline auto decode_csrrw_rs1(uint32_t insn) -> uint8_t
30	{
31	  return static_cast<uint8_t>((insn >> 15) & 0x1Fu);
32	}
33	
34	class CsrTrigger
35	{
36	public:
37	  void scan_buffer(std::span<const uint8_t> code, uint64_t base_pc)
38	  {
39	    std::size_t i = 0;
40	    while (i + sizeof(uint16_t) <= code.size()) {
41	      uint16_t lo = 0;
42	      std::memcpy(&lo, code.data() + i, sizeof(lo));
43	
44	      const bool is_32 = (lo & 0x3u) == 0x3u;
45	      if (is_32) {
46	        if (i + sizeof(uint32_t) > code.size()) break;
47	        uint32_t insn = 0;
48	        std::memcpy(&insn, code.data() + i, sizeof(insn));
49	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
50	        if (hybrid_match_handoff_insn(insn, &kind)) {
51	          hits_.insert_or_assign(base_pc + i, CsrTriggerHit{kind, insn});
52	        }
53	        i += sizeof(uint32_t);
54	      } else {
55	        i += sizeof(uint16_t);
56	      }
57	    }
58	  }
59	
60	  auto lookup(uint64_t pc) const -> std::optional<CsrTriggerHit>
61	  {
62	    if (auto it = hits_.find(pc); it != hits_.end()) return it->second;
63	    return std::nullopt;
64	  }
65	
66	  auto empty() const -> bool { return hits_.empty(); }
67	
68	private:
69	  std::unordered_map<uint64_t, CsrTriggerHit> hits_;
70	};
71	
72	}  // namespace hybrid
