1	// Spawns qemu-system-riscv64 with -gdb tcp::PORT -S -semihosting and
2	// restores architectural state via the gdbstub before sending `c`. Waits
3	// for QEMU to exit and propagates its process exit code.
4	//
5	// Used by main.cpp when `Simulator::run()` returns kExitHandoffToQemu and
6	// `--qemu-binary` is set.
7	
8	#pragma once
9	
10	#include "hybrid/exit_codes.hpp"
11	#include "hybrid/gdbstub_session.hpp"
12	#include "hybrid/state_abi.h"
13	
14	#include <spdlog/spdlog.h>
15	
16	#include <arpa/inet.h>
17	#include <netinet/in.h>
18	#include <sys/socket.h>
19	#include <sys/types.h>
20	#include <sys/wait.h>
21	#include <unistd.h>
22	
23	#include <cerrno>
24	#include <chrono>
25	#include <cstdint>
26	#include <cstdlib>
27	#include <cstring>
28	#include <stdexcept>
29	#include <string>
30	#include <thread>
31	#include <vector>
32	
33	namespace hybrid
34	{
35	
36	namespace detail
37	{
38	
39	inline auto pick_free_port() -> uint16_t
40	{
41	  const int s = ::socket(AF_INET, SOCK_STREAM, 0);
42	  if (s < 0)
43	    throw std::runtime_error("pick_free_port: socket");
44	
45	  sockaddr_in addr{};
46	  addr.sin_family      = AF_INET;
47	  addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
48	  addr.sin_port        = 0;
49	
50	  if (::bind(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) < 0) {
51	    ::close(s);
52	    throw std::runtime_error("pick_free_port: bind");
53	  }
54	  socklen_t len = sizeof(addr);
55	  if (::getsockname(s, reinterpret_cast<sockaddr*>(&addr), &len) < 0) {
56	    ::close(s);
57	    throw std::runtime_error("pick_free_port: getsockname");
58	  }
59	  ::close(s);
60	  return ntohs(addr.sin_port);
61	}
62	
63	inline auto connect_loopback(uint16_t port,
64	                             std::chrono::milliseconds timeout) -> int
65	{
66	  const auto deadline = std::chrono::steady_clock::now() + timeout;
67	  while (std::chrono::steady_clock::now() < deadline) {
68	    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
69	    if (s < 0)
70	      throw std::runtime_error("connect_loopback: socket");
71	    sockaddr_in addr{};
72	    addr.sin_family      = AF_INET;
73	    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
74	    addr.sin_port        = htons(port);
75	    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
76	      return s;
77	    ::close(s);
78	    std::this_thread::sleep_for(std::chrono::milliseconds(20));
79	  }
80	  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
81	                           "gdbstub");
82	}
83	
84	inline auto spawn_qemu(const std::string& binary,
85	                       const std::string& elf,
86	                       uint16_t gdb_port) -> pid_t
87	{
88	  const pid_t pid = ::fork();
89	  if (pid < 0)
90	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
91	                             + std::strerror(errno));
92	  if (pid == 0) {
93	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
94	    std::vector<const char*> argv;
95	    argv.push_back(binary.c_str());
96	    argv.push_back("-M");
97	    argv.push_back("virt");
98	    argv.push_back("-bios");
99	    argv.push_back("none");
100	    argv.push_back("-nographic");
101	    argv.push_back("-semihosting-config");
102	    argv.push_back("enable=on,target=native");
103	    argv.push_back("-kernel");
104	    argv.push_back(elf.c_str());
105	    argv.push_back("-gdb");
106	    argv.push_back(gdb_arg.c_str());
107	    argv.push_back("-S");
108	    argv.push_back(nullptr);
109	
110	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
111	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
112	                 std::strerror(errno));
113	    ::_exit(127);
114	  }
115	  return pid;
116	}
117	
118	}  // namespace detail
119	
120	// Restores x1..x31 and PC into the QEMU vCPU via the gdbstub at `port`,
121	// then continues. Caller is responsible for waitpid().
122	inline void restore_state_via_gdbstub(uint16_t port,
123	                                      const hybrid_state_v1& state)
124	{
125	  spdlog::info("hybrid handback: connecting to gdbstub on tcp::{}", port);
126	  const int fd = detail::connect_loopback(port, std::chrono::seconds(5));
127	  spdlog::info("hybrid handback: connected, restoring state");
128	  gdbstub::Session sess{fd};
129	
130	  for (unsigned i = 1; i < 32; ++i) {
131	    const auto pkt = gdbstub::encode_p_packet(i, state.gpr[i]);
132	    auto reply =
133	      sess.send_command(std::string_view{pkt}.substr(1, pkt.size() - 4));
134	    if (reply != "OK")
135	      throw std::runtime_error(
136	        "gdbstub: P packet for x" + std::to_string(i) + " replied " + reply);
137	  }
138	
139	  // RV64 GDB register layout: x0..x31 = 0..31, pc = 32.
140	  const auto pc_pkt = gdbstub::encode_p_packet(32, state.pc);
141	  auto reply = sess.send_command(
142	    std::string_view{pc_pkt}.substr(1, pc_pkt.size() - 4));
143	  if (reply != "OK")
144	    throw std::runtime_error("gdbstub: P32 (pc) replied " + reply);
145	
146	  spdlog::info("hybrid handback: continuing target");
147	  sess.cont();
148	}
149	
150	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
151	// status (or 128 + signal for abnormal termination).
152	inline auto run_qemu_handback(const std::string& qemu_binary,
153	                              const std::string& elf_path,
154	                              const hybrid_state_v1& state) -> int
155	{
156	  const auto port = detail::pick_free_port();
157	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
158	               qemu_binary, port);
159	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port);
160	
161	  try {
162	    restore_state_via_gdbstub(port, state);
163	  } catch (...) {
164	    ::kill(pid, SIGKILL);
165	    int wstat = 0;
166	    ::waitpid(pid, &wstat, 0);
167	    throw;
168	  }
169	
170	  int wstat = 0;
171	  if (::waitpid(pid, &wstat, 0) < 0)
172	    throw std::runtime_error(std::string{"waitpid: "}
173	                             + std::strerror(errno));
174	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
175	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
176	  return -1;
177	}
178	
179	}  // namespace hybrid
