1	// TCP-backed GDB Remote Serial Protocol session. Wraps an already-connected
2	// socket fd; the higher-level qemu_handback orchestration spawns QEMU and
3	// passes the fd in.
4	
5	#pragma once
6	
7	#include "hybrid/gdbstub_client.hpp"
8	
9	#include <spdlog/spdlog.h>
10	
11	#include <sys/socket.h>
12	#include <unistd.h>
13	
14	#include <cerrno>
15	#include <cstdint>
16	#include <cstring>
17	#include <stdexcept>
18	#include <string>
19	#include <string_view>
20	
21	namespace hybrid::gdbstub
22	{
23	
24	class Session
25	{
26	public:
27	  explicit Session(int fd)
28	      : fd_{fd}
29	  {}
30	
31	  Session(const Session&)            = delete;
32	  Session& operator=(const Session&) = delete;
33	
34	  Session(Session&& o) noexcept
35	      : fd_{o.fd_}
36	  {
37	    o.fd_ = -1;
38	  }
39	
40	  ~Session()
41	  {
42	    if (fd_ >= 0) ::close(fd_);
43	  }
44	
45	  // Sends $body#cs, waits for `+` ack, reads and acks one response packet,
46	  // returns the response body. Throws on socket errors or protocol violations.
47	  auto send_command(std::string_view body) -> std::string
48	  {
49	    const auto pkt = encode_packet(body);
50	    spdlog::debug("gdbstub send: {}", pkt);
51	    send_raw(pkt);
52	    expect_ack();
53	    auto resp = recv_packet();
54	    spdlog::debug("gdbstub recv: {}", resp);
55	    send_raw("+");
56	    return resp;
57	  }
58	
59	  // Sends $c#cs and waits only for the ack. The target runs until it exits
60	  // on its own (e.g., semihosting) -- caller waitpid()s the QEMU process.
61	  void cont()
62	  {
63	    send_raw(encode_continue());
64	    expect_ack();
65	  }
66	
67	private:
68	  void send_raw(std::string_view data)
69	  {
70	    std::size_t off = 0;
71	    while (off < data.size()) {
72	      const ssize_t n =
73	        ::send(fd_, data.data() + off, data.size() - off, 0);
74	      if (n < 0) {
75	        if (errno == EINTR) continue;
76	        throw std::runtime_error(std::string{"gdbstub::Session::send: "}
77	                                 + std::strerror(errno));
78	      }
79	      off += static_cast<std::size_t>(n);
80	    }
81	  }
82	
83	  auto recv_byte() -> char
84	  {
85	    char c;
86	    while (true) {
87	      const ssize_t n = ::recv(fd_, &c, 1, 0);
88	      if (n == 1) return c;
89	      if (n == 0)
90	        throw std::runtime_error("gdbstub::Session: peer closed");
91	      if (errno == EINTR) continue;
92	      throw std::runtime_error(std::string{"gdbstub::Session::recv: "}
93	                               + std::strerror(errno));
94	    }
95	  }
96	
97	  void expect_ack()
98	  {
99	    const auto c = recv_byte();
100	    if (c == '+') return;
101	    if (c == '-')
102	      throw std::runtime_error("gdbstub::Session: peer requested resend");
103	    throw std::runtime_error(
104	      std::string{"gdbstub::Session: expected ack, got "} + c);
105	  }
106	
107	  // Reads `$body#cs`, validates checksum, returns body. Discards any leading
108	  // out-of-frame bytes (some stubs emit unsolicited stop notifications).
109	  auto recv_packet() -> std::string
110	  {
111	    while (recv_byte() != '$') {}
112	    std::string body;
113	    while (true) {
114	      const auto c = recv_byte();
115	      if (c == '#') break;
116	      body.push_back(c);
117	    }
118	    const auto cs_hi = recv_byte();
119	    const auto cs_lo = recv_byte();
120	    const std::string framed = "$" + body + "#" + cs_hi + cs_lo;
121	    auto parsed = parse_packet(framed);
122	    if (!parsed)
123	      throw std::runtime_error("gdbstub::Session: bad checksum");
124	    return *parsed;
125	  }
126	
127	  int fd_;
128	};
129	
130	}  // namespace hybrid::gdbstub
