10	
11	struct DmiBus
12	{
13	  virtual ~DmiBus() = default;
14	  virtual void write(uint8_t reg, uint32_t value) = 0;
15	  virtual auto read(uint8_t reg) -> uint32_t = 0;
16	};
17	
18	class ResumeDriver
19	{
20	public:
21	  static constexpr uint8_t kData0      = 0x04;
22	  static constexpr uint8_t kData1      = 0x05;
23	  static constexpr uint8_t kDmcontrol  = 0x10;
24	  static constexpr uint8_t kDmstatus   = 0x11;
25	  static constexpr uint8_t kAbstractcs = 0x16;
26	  static constexpr uint8_t kCommand    = 0x17;
27	
28	  static constexpr uint16_t kCsrDpc = 0x7B1;
29	
30	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
31	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
32	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
33	
34	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
35	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
36	
37	  static constexpr uint32_t kAbstractcsBusy = 1u << 12;
38	
39	  // Bounded so a buggy DM cannot hang the host.
40	  static constexpr unsigned kPollIterations = 1024;
41	
42	  explicit ResumeDriver(DmiBus& bus)
43	      : bus_{bus}
44	  {}
45	
46	  void resume(const hybrid_state_v1& state)
47	  {
48	    if (state.magic != HYBRID_STATE_MAGIC)
49	      throw std::runtime_error("ResumeDriver::resume: bad magic");
50	    if (state.version != HYBRID_STATE_VERSION)
51	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
52	
53	    // dmactive must transition 0->1 in its own write before any other
54	    // DMCONTROL bit is honored (RISC-V Debug Spec).
55	    bus_.write(kDmcontrol, kDmcontrolDmactive);
56	    request_halt();
57	    poll_until_set(kDmstatus, kDmstatusAllhalted);
58	
59	    // x0 is hard-wired zero; skip it.
60	    for (uint16_t i = 1; i < 32; ++i)
61	      write_64bit_register(regno_gpr(i), state.gpr[i]);
62	
63	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
64	
65	    request_resume();
66	    poll_until_set(kDmstatus, kDmstatusAllresumeack);
67	  }
68	
69	private:
70	  void request_halt()
71	  {
72	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
73	  }
74	
75	  void request_resume()
76	  {
77	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
78	  }
79	
80	  void write_64bit_register(uint16_t regno, uint64_t value)
81	  {
82	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
83	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
84	    bus_.write(kCommand,
85	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
86	    poll_until_clear(kAbstractcs, kAbstractcsBusy);
87	  }
88	
89	  void poll_until_set(uint8_t reg, uint32_t mask)
90	  {
91	    for (unsigned i = 0; i < kPollIterations; ++i)
92	      if ((bus_.read(reg) & mask) == mask) return;
93	    throw std::runtime_error("ResumeDriver: poll_until_set timed out");
94	  }
95	
96	  void poll_until_clear(uint8_t reg, uint32_t mask)
97	  {
98	    for (unsigned i = 0; i < kPollIterations; ++i)
99	      if ((bus_.read(reg) & mask) == 0) return;
100	    throw std::runtime_error("ResumeDriver: poll_until_clear timed out");
101	  }
102	
103	  DmiBus& bus_;
104	};
105	
