19	constexpr uint8_t kDmcontrol  = 0x10;
20	constexpr uint8_t kDmstatus   = 0x11;
21	constexpr uint8_t kAbstractcs = 0x16;
22	constexpr uint8_t kCommand    = 0x17;
23	constexpr uint8_t kData0      = 0x04;
24	constexpr uint8_t kData1      = 0x05;
25	
26	constexpr uint16_t kCsrDpc = 0x7B1;
