40	// Recording bus. For Abstract Command reads, look up the requested regno in
41	// `regfile` and latch the value into pending_data0/1 so the next DATA0/DATA1
42	// reads return it. This mirrors a real DM that has just completed an
43	// abstract read.
44	struct RecordingBus final : hybrid::DmiBus
45	{
46	  std::vector<DmiOp> ops;
47	  uint32_t dmstatus_value = 0;
48	  uint32_t abstractcs_value = 0;
49	  std::unordered_map<uint16_t, uint64_t> regfile;
50	  uint32_t pending_data0 = 0;
51	  uint32_t pending_data1 = 0;
52	
53	  void write(uint8_t reg, uint32_t value) override
54	  {
55	    ops.push_back({DmiOp::Kind::Write, reg, value});
56	    if (reg == kCommand) {
57	      const uint16_t regno   = value & 0xffffu;
58	      const bool is_write    = ((value >> 16) & 1u) != 0;
59	      if (!is_write) {
60	        const auto it = regfile.find(regno);
61	        const uint64_t v = (it == regfile.end()) ? 0 : it->second;
62	        pending_data0 = static_cast<uint32_t>(v & 0xffffffffu);
63	        pending_data1 = static_cast<uint32_t>((v >> 32) & 0xffffffffu);
64	      }
65	    }
66	  }
67	
68	  auto read(uint8_t reg) -> uint32_t override
69	  {
70	    ops.push_back({DmiOp::Kind::Read, reg, 0});
71	    if (reg == kDmstatus)   return dmstatus_value;
72	    if (reg == kAbstractcs) return abstractcs_value;
73	    if (reg == kData0)      return pending_data0;
74	    if (reg == kData1)      return pending_data1;
75	    return 0;
76	  }
77	};
78	
79	}  // namespace
