51	  void write(uint8_t reg, uint32_t value) override
52	  {
53	    ops.push_back({DmiOp::Kind::Write, reg, value});
54	    if (reg == kCommand) {
55	      const uint16_t regno = value & 0xffffu;
56	      const bool is_write  = ((value >> 16) & 1u) != 0;
57	      if (!is_write) {
