59	        const uint64_t v = (it == regfile.end()) ? 0 : it->second;
60	        pending_data0 = static_cast<uint32_t>(v & 0xffffffffu);
61	        pending_data1 = static_cast<uint32_t>((v >> 32) & 0xffffffffu);
