104	TEST_CASE("csr_trigger: 2-byte stride skips compressed insns and aligns 4-byte insns")
105	{
106	  // Layout:
107	  //   0x80000000: c.addi x1, 1     (2 bytes, RVC: bits[1:0] != 0b11)
108	  //   0x80000002: csrwi 0x7C0, 1   (4 bytes)
109	  //   0x80000006: c.nop            (2 bytes)
110	  hybrid::CsrTrigger trig;
111	  alignas(uint32_t) std::array<uint8_t, 8> bytes{};
112	  // c.addi x1, 1 = 0x0085 (op=01, funct3=000, rd=x1, imm=1) -- rvc bits[1:0]=01
113	  // Use a placeholder 16-bit RVC pattern: 0x0085
114	  bytes[0] = 0x85;
115	  bytes[1] = 0x00;
116	  // csrwi 0x7C0, 1 = 0x7C00D073 (little-endian: 73 D0 00 7C)
117	  const uint32_t exit_insn = encode_csrrwi(0, 0x7C0, 1);
118	  std::memcpy(&bytes[2], &exit_insn, sizeof(exit_insn));
119	  // c.nop = 0x0001 (rvc bits[1:0]=01)
120	  bytes[6] = 0x01;
121	  bytes[7] = 0x00;
122	
123	  trig.scan_buffer(std::span<const uint8_t>{bytes.data(), bytes.size()},
124	                   /*base_pc=*/0x80000000);
125	
126	  // Only the 4-byte csrwi at 0x80000002 should match.
127	  CHECK_FALSE(trig.lookup(0x80000000).has_value());
128	  REQUIRE(trig.lookup(0x80000002));
129	  CHECK(trig.lookup(0x80000002)->kind == HYBRID_HANDOFF_EXIT);
130	  CHECK_FALSE(trig.lookup(0x80000006).has_value());
