1	// Recognises csrrw/csrrwi rd=0 to CSR 0x7C0, the magic handoff trigger. Pure
2	// bit pattern; the same predicate is consumed by the QEMU plugin (C) and by
3	// the vsim-side PC pre-scan (C++).
4	
5	#include "hybrid/insn_match.h"
6	
7	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
8	#include <doctest.h>
9	
10	#include <cstdint>
11	
12	namespace {
13	
14	// Build a SYSTEM-opcode csrrwi insn: csrrwi rd, csr, uimm.
15	auto encode_csrrwi(uint32_t rd, uint32_t csr, uint32_t uimm) -> uint32_t
16	{
17	  return (csr << 20) | (uimm << 15) | (0b101u << 12) | (rd << 7) | 0x73u;
18	}
19	
20	// Build a SYSTEM-opcode csrrw insn: csrrw rd, csr, rs1.
21	auto encode_csrrw(uint32_t rd, uint32_t csr, uint32_t rs1) -> uint32_t
22	{
23	  return (csr << 20) | (rs1 << 15) | (0b001u << 12) | (rd << 7) | 0x73u;
24	}
25	
26	}  // namespace
27	
28	TEST_CASE("csrrwi rd=0, csr=0x7C0, uimm=0 (enter) matches and decodes uimm")
29	{
30	  const auto insn = encode_csrrwi(0, 0x7C0, 0);
31	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
32	  CHECK(hybrid_match_handoff_insn(insn, &kind));
33	  CHECK(kind == HYBRID_HANDOFF_ENTER);
34	}
35	
36	TEST_CASE("csrrwi rd=0, csr=0x7C0, uimm=1 (exit) matches and decodes uimm")
37	{
38	  const auto insn = encode_csrrwi(0, 0x7C0, 1);
39	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
40	  CHECK(hybrid_match_handoff_insn(insn, &kind));
41	  CHECK(kind == HYBRID_HANDOFF_EXIT);
42	}
43	
44	TEST_CASE("csrrw rd=0, csr=0x7C0 matches as runtime kind (rs1-borne)")
45	{
46	  const auto insn = encode_csrrw(0, 0x7C0, /*rs1=*/5);
47	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
48	  CHECK(hybrid_match_handoff_insn(insn, &kind));
49	  CHECK(kind == HYBRID_HANDOFF_RUNTIME);
50	}
51	
52	TEST_CASE("a write to a different CSR does not match")
53	{
54	  const auto insn = encode_csrrwi(0, 0x7C1, 0);
55	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
56	  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
57	}
58	
59	TEST_CASE("non-zero rd disqualifies (only csrw, not csrrw with rd!=0)")
60	{
61	  const auto insn = encode_csrrwi(/*rd=*/3, 0x7C0, 0);
62	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
63	  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
64	}
65	
66	TEST_CASE("non-SYSTEM opcode does not match")
67	{
68	  const uint32_t addi = (1u << 20) | (0u << 15) | (0u << 12) | (0u << 7) | 0x13;
69	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
70	  CHECK_FALSE(hybrid_match_handoff_insn(addi, &kind));
71	}
72	
73	TEST_CASE("csrrs (a read with set-bits) to 0x7C0 does not match")
74	{
75	  // funct3 = 010 = csrrs, not 001/101.
76	  const uint32_t insn =
77	    (0x7C0u << 20) | (0u << 15) | (0b010u << 12) | (0u << 7) | 0x73u;
78	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
79	  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
80	}
81	
82	TEST_CASE("uimm=2 on csrwi is rejected (only 0 and 1 carry meaning)")
83	{
84	  const auto insn = encode_csrrwi(0, 0x7C0, 2);
85	  hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
86	  CHECK_FALSE(hybrid_match_handoff_insn(insn, &kind));
87	}
