295	  void reset()
296	  {
297	    static constexpr int core_num = CPU::NDS_NHART;
298	    static constexpr int reset_val = (1 << core_num) - 1;
299	
300	    platform.resetn.write(0);
301	    auto saved = context_config;
302	    context_config = {};
303	    this->run(1);
304	    context_config = saved;
305	
306	    for (size_t i = 0; i < platform.reset_vector.size(); ++i)
307	      spdlog::info("hart {} reset vector: {:#x}", i,
308	                   (uint64_t) platform.reset_vector[i].read());
309	
310	    platform.resetn.write(reset_val);
311	
312	    if (context_config.continue_from)
313	      restore_context(context_config.dir);
314	  }
