412	  auto check_hybrid_handoff() -> std::optional<int>
413	  {
414	    if constexpr (!requires { cpu.get_committed_pc(); }) {
415	      return std::nullopt;
416	    } else {
417	      const auto committed = cpu.get_committed_pc();
418	      if (committed.empty()) return std::nullopt;
419	      for (const auto pc: committed[0]) {
420	        auto state = hybrid_handoff_->on_retire(
421	          pc, [&](uint8_t r) -> uint64_t {
422	            if constexpr (requires { cpu.get_gpr(r); }) {
423	              return cpu.get_gpr(r);
424	            }
425	            return 0;
426	          });
427	        if (state) {
428	          spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
429	                       pc, hybrid_state_path_);
430	          std::ofstream f(hybrid_state_path_, std::ios::binary);
431	          f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
432	          return hybrid::kExitHandoffToQemu;
433	        }
434	      }
435	      return std::nullopt;
436	    }
437	  }
