291	  if (!args.shared_mem_path.empty()) {
292	    if (args.shared_mem_size == 0)
293	      throw std::runtime_error(
294	        "--shared-mem-path requires --shared-mem-size > 0");
295	    shared_ram.emplace(args.shared_mem_path, args.shared_mem_size);
296	  } else if (args.shared_mem_size != 0) {
297	    throw std::runtime_error(
298	      "--shared-mem-size requires --shared-mem-path");
299	  }
300	
301	  // run simulation
302	  const auto do_sim = [&]<typename CPU>() -> int {
303	    Simulator<CPU> sim{
304	      "sim", shared_ram ? shared_ram->span() : std::span<uint8_t>{}};
305	
306	    if (args.memmap) {
307	      sim.platform.interconnect.dump_region();
308	      return 0;
309	    }
310	
311	    sim.set_mem_latency(args.mem_latency);
312	
313	    if (!args.ilm_file.empty())
314	      sim.load_image(args.ilm_file, MEM_TYPE::ILM);
315	
316	    if (!args.dlm_file.empty())
317	      sim.load_image(args.dlm_file, MEM_TYPE::DLM);
318	
319	    // End of elaboration
320	    sc_core::sc_start(sc_core::SC_ZERO_TIME);
321	
322	    const auto t0 = std::chrono::steady_clock::now();
323	
324	    if (!args.waveform_file.empty())
325	      sim.enable_waveform(args.waveform_file);
326	
327	    if (!args.pc_trace_file.empty())
