24	
25	template<typename Cpu>
26	auto run_smoke(const std::string& elf_path, const std::string& state_path) -> int
27	{
28	  Simulator<Cpu> sim{"sim"};
29	  sim.load_elf(elf_path);
30	
31	  sc_core::sc_start(sc_core::SC_ZERO_TIME);
32	  sim.reset();
33	  sim.enable_hybrid_handoff(elf_path, state_path);
34	
35	  spdlog::info("handoff_smoke: starting run");
36	  const auto rc = sim.run();
37	
38	  if (rc != hybrid::kExitHandoffToQemu) {
39	    spdlog::error("handoff_smoke FAIL: run() returned {} (expected {})",
40	                  rc, hybrid::kExitHandoffToQemu);
41	    return 1;
42	  }
43	
44	  std::ifstream f(state_path, std::ios::binary);
45	  if (!f) {
46	    spdlog::error("handoff_smoke FAIL: state file {} not readable",
47	                  state_path);
48	    return 2;
49	  }
50	  hybrid_state_v1 state{};
51	  f.read(reinterpret_cast<char*>(&state), sizeof(state));
52	  if (!f) {
53	    spdlog::error("handoff_smoke FAIL: short read of state file");
54	    return 3;
55	  }
56	  if (state.magic != HYBRID_STATE_MAGIC) {
57	    spdlog::error("handoff_smoke FAIL: bad magic 0x{:08x} (expected 0x{:08x})",
58	                  state.magic, HYBRID_STATE_MAGIC);
59	    return 4;
60	  }
61	  if (state.gpr[12] != 3) {
62	    spdlog::error("handoff_smoke FAIL: gpr[12] (a2) = {} (expected 3)",
63	                  state.gpr[12]);
64	    return 5;
65	  }
66	
67	  spdlog::info("handoff_smoke PASS: drained pc=0x{:x}, a2={}",
68	               state.pc, state.gpr[12]);
69	  return 0;
70	}
