13	template<std::size_t AddrWidth, std::size_t DataWidth>
14	class SystemCDmiBus final : public DmiBus
15	{
16	public:
17	  using ahb_manager = ahb::manager<AddrWidth, DataWidth>;
18	
19	  SystemCDmiBus(ahb_manager& ahb, const sc_core::sc_time& cycle)
20	      : ahb_{ahb}, cycle_{cycle}
21	  {}
22	
23	  void write(uint8_t reg, uint32_t value) override
24	  {
25	    static_cast<void>(ahb_.write(typename ahb_manager::addr_type(reg << 2),
26	                                 typename ahb_manager::data_type(value)));
27	    drain();
28	  }
29	
30	  auto read(uint8_t reg) -> uint32_t override
31	  {
32	    ahb_.read(typename ahb_manager::addr_type(reg << 2));
33	    drain();
34	    return uint32_t(ahb_.txn.data.to_uint64());
35	  }
36	
37	private:
38	  void drain()
39	  {
40	    while (ahb_.txn.is_busy()) sc_core::sc_start(cycle_);
41	    if (ahb_.txn.phase == ahb_manager::transaction::phase::error)
42	      throw std::runtime_error("SystemCDmiBus: DMI transaction error");
43	  }
44	
45	  ahb_manager& ahb_;
46	  sc_core::sc_time cycle_;
47	};
