19	namespace {
20	
21	using RD = hybrid::ResumeDriver;
22	
23	template<typename Bus>
24	auto poll_until(Bus& bus, uint8_t reg, uint32_t mask, bool want_set) -> bool
25	{
26	  for (unsigned i = 0; i < RD::kPollIterations; ++i) {
27	    const auto v = bus.read(reg);
28	    const bool is_set = (v & mask) == mask;
29	    if (is_set == want_set) return true;
30	  }
31	  return false;
32	}
33	
34	template<typename Cpu>
35	auto run_smoke(const std::string& elf_path) -> int
36	{
37	  Simulator<Cpu> sim{"sim"};
38	  sim.load_elf(elf_path);
39	
40	  sc_core::sc_start(sc_core::SC_ZERO_TIME);
41	  sim.reset();
42	
43	  using PLATFORM = ::Platform<platform_config<Cpu>>;
44	  hybrid::SystemCDmiBus<PLATFORM::dmi_addr_width, PLATFORM::dmi_data_width> bus{
45	    sim.platform.dmi, sim.platform.clk.period()};
46	
47	  spdlog::info("dmi_smoke: probing DMCONTROL.dmactive");
48	  bus.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
49	  const auto dmcontrol = bus.read(RD::kDmcontrol);
50	  if ((dmcontrol & RD::kDmcontrolDmactive) == 0) {
51	    spdlog::error("dmi_smoke FAIL: dmactive did not stick (dmcontrol=0x{:08x})",
52	                  dmcontrol);
53	    return 1;
54	  }
55	
56	  spdlog::info("dmi_smoke: requesting halt");
57	  bus.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
58	  if (!poll_until(bus, RD::kDmstatus, RD::kDmstatusAllhalted, /*want_set=*/true))
59	  {
60	    spdlog::error("dmi_smoke FAIL: did not reach allhalted within budget");
61	    return 2;
62	  }
63	  spdlog::info("dmi_smoke: halted");
64	
65	  constexpr uint16_t kTestGpr = 10;  // a0
66	  constexpr uint64_t kPattern = 0xDEADBEEFCAFEBABEULL;
67	  const auto cmd_write =
68	    hybrid::access_register_command(hybrid::regno_gpr(kTestGpr),
69	                                    hybrid::AarSize::Bits64,
70	                                    /*write=*/true);
71	  const auto cmd_read =
72	    hybrid::access_register_command(hybrid::regno_gpr(kTestGpr),
73	                                    hybrid::AarSize::Bits64,
74	                                    /*write=*/false);
75	
76	  bus.write(RD::kData0, uint32_t(kPattern & 0xFFFFFFFFu));
77	  bus.write(RD::kData1, uint32_t((kPattern >> 32) & 0xFFFFFFFFu));
78	  bus.write(RD::kCommand, cmd_write);
79	  if (!poll_until(bus, RD::kAbstractcs, RD::kAbstractcsBusy, /*want_set=*/false))
80	  {
81	    spdlog::error("dmi_smoke FAIL: abstract write busy did not clear");
82	    return 3;
83	  }
84	
85	  bus.write(RD::kCommand, cmd_read);
86	  if (!poll_until(bus, RD::kAbstractcs, RD::kAbstractcsBusy, /*want_set=*/false))
87	  {
88	    spdlog::error("dmi_smoke FAIL: abstract read busy did not clear");
89	    return 4;
90	  }
